        }
        node := &nodeX{Cache: cache}
        tx, ty, ok := bind_d(node, tokenX(h.ID), []int{w.PlayerX, w.PlayerY, h.X, h.Y})
        if !ok {
                return sim.MoveRow{}, false
        }
        legal := e4.StepLegal(w, h.X, h.Y, tx, ty)
        visible := e4.PlayerSees(w, tx, ty)
        row := sim.MoveRow{
                Turn:  w.Turn,
                Actor: h.ID,
                FromX: h.X,
                FromY: h.Y,
                ToX:   tx,
                ToY:   ty,
                Kind:  "step",
                Legal: legal && visible,
        }
        h.X, h.Y = tx, ty
        w.Hostile[idx] = h
        return row, true
}
