                Effects:    rowsFromC2(c2.ItemsFor(snapToC2(wResume.Effects), wResume.Turn)),
                Records:    recPath,
                Log:        logPath,
        }, nil
}

func flushRows(recPath, logPath, name string, moves []MoveRow) {
        rec, _ := os.Create(recPath)
        defer rec.Close()
        for _, m := range moves {
                b, _ := json.Marshal(m)
                _, _ = rec.Write(append(b, '\n'))
        }
        log, _ := os.Create(logPath)
        defer log.Close()
        for _, m := range moves {
